fun solve(grid: Array<Array<Long>>, x: Long, y: Long, k: Long): Array<Array<Long>> {
    val result = grid.map { it.toTypedArray() }.toTypedArray()

    val submatrix = Array(k) { i ->
        Array(k) { j ->
            result[x.toInt() + i][y.toInt() + j]
        }
    }

    val reversedSubmatrix = submatrix.reversed()

    reversedSubmatrix.forEachWithIndex { row, i ->
        row.forEachWithIndex { value, j ->
            result[x.toInt() + i][y.toInt() + j] = value
        }
    }

    return result
}
