fun solve(grid: Array<Array<Long>>, x: Long, y: Long, k: Long): Array<Array<Long>> {
    // Create a copy of the grid to avoid modifying the original
    val result = grid.map { it.copyOf() }.toTypedArray()

    // Extract the submatrix
    val submatrix = Array(k) { i ->
        Array(k) { j ->
            result[x.toInt() + i][y.toInt() + j]
        }
    }

    // Reverse the submatrix
    val reversedSubmatrix = submatrix.reversed()

    // Put the reversed submatrix back into the result
    for (i in reversedSubmatrix.indices) {
        for (j in reversedSubmatrix[i].indices) {
            result[x.toInt() + i][y.toInt() + j] = reversedSubmatrix[i][j]
        }
    }

    return result
}
